effect.shader:
const vec3 luminanceWeighting = vec3(0.2126, 0.7152, 0.0722);

void main() {
    vec2 texelSize = 1.0 / getTexSize(inputImg.size);
    vec2 center = vec2(0.5 + centerPoint.x/500., 0.5 - centerPoint.y/500.);
    vec2 v = acScreenNorm.st - (vec4(center,0.0,1.0) * acLayerToScreen).xy;
    float speed = length(strength / 2.0 / texelSize);
    speed *= length( acLayerNorm.st - center );
    //int nSamples = int(clamp(speed, 1.01, 200.01));
    int nSamples = int(quality);
    vec4 baseColor = texture2DCv(inputImg.texture,acScreenNorm.st);
    vec2 vnorm = normalize(v)*texelSize*speed;
    vec2 offsetScale = vec2(1., 1.);
    if( acScreenSize.y > acScreenSize.x ) {
        offsetScale.x *= acScreenSize.x / acScreenSize.y;
    } else {
        offsetScale.y *= acScreenSize.y / acScreenSize.x;
    }

    float actualSamples = 1.0;
    vec4 outColor = vec4(0.);
    for(int i=1; i<nSamples; i++ ) {
        float p = float(i) / float(nSamples - 1);
        vec2 offs = vnorm * p;
        offs *= offsetScale;

        vec4 texColor = texture2DCv(inputImg.texture, acScreenNorm.st-offs);

        float luminance = dot(texColor.rgb - thresholdColor.rgb, luminanceWeighting);

        outColor += luminance > threshold ? mix(texColor,fillColor,blend)*(1.-p) : vec4(0.0);
        actualSamples += luminance > threshold ? 1.0 : 0.0;
    }
    gl_FragColor = baseColor + outColor * intensity / float(nSamples);
}
